        object response = await this.myriadPublicGetOrdersHash(this.extend(new Dictionary<string, object>() {
            { "hash", id },
        }, parameters));
        object market = null;
        if (isTrue(!isEqual(outcome, null)))
        {
            market = await this.loadOutcome(outcome);
